// Java Kafka producer with idempotence and strong durability
Properties props = new Properties();
props.put("bootstrap.servers", "kafka:9092");
props.put("acks", "all"); // wait for all in-sync replicas
props.put("retries", 5);
props.put("enable.idempotence", "true"); // avoid duplicates on retry
props.put("batch.size", 16384);
props.put("linger.ms", 5);
props.put("compression.type", "lz4");
props.put("key.serializer", "org.apache.kafka.common.serialization.StringSerializer");
props.put("value.serializer", "org.apache.kafka.common.serialization.StringSerializer");

KafkaProducer<String, String> producer = new KafkaProducer<>(props);
ProducerRecord<String, String> record = new ProducerRecord<>("events", "user-123", "clicked_button");
producer.send(record, (metadata, ex) -> {
  if (ex != null) System.err.println("Send failed: " + ex);
  else System.out.println("Sent to partition " + metadata.partition());
});
producer.flush();
producer.close();
